// Regular function — has its own 'this'
function Timer() {
  this.seconds = 0;
  setInterval(function() {
    this.seconds++; //  'this' is undefined in strict / window in sloppy
    console.log(this.seconds);
  }, 1000);
}

// Arrow function — inherits 'this' from Timer
function TimerFixed() {
  this.seconds = 0;
  setInterval(() => {
    this.seconds++; //  'this' is TimerFixed instance
    console.log(this.seconds);
  }, 1000);
}

