js.promises.code_example:
// Creating a Promise
function fetchUser(id) {
  return new Promise((resolve, reject) => {
    if (id <= 0) {
      reject(new Error('Invalid ID'));
    } else {
      setTimeout(() => resolve({ id, name: 'Alice' }), 500);
    }
  });
}

// Consuming with .then / .catch
fetchUser(1)
  .then(user => console.log(user))   // { id: 1, name: 'Alice' }
  .catch(err => console.error(err))
  .finally(() => console.log('Done'));

// Promise.all — all must succeed
Promise.all([fetchUser(1), fetchUser(2)])
  .then(([u1, u2]) => console.log(u1, u2))
  .catch(err => console.error('One failed:', err));

// Promise.allSettled — get every result
Promise.allSettled([fetchUser(1), fetchUser(-1)])
  .then(results => results.forEach(r => console.log(r.status)));

js.async_await.code_example:
// Basic async/await
async function getUser(id) {
  const response = await fetch(`/api/users/${id}`);
  const user = await response.json();
  return user;
}

// Error handling
async function safeGetUser(id) {
  try {
    const user = await getUser(id);
    console.log(user);
  } catch (error) {
    console.error('Failed:', error.message);
  } finally {
    console.log('Request complete');
  }
}

//  Sequential (slow — waits one by one)
async function slow() {
  const u1 = await getUser(1); // wait...
  const u2 = await getUser(2); // then wait...
}

//  Parallel (fast — both requests fire at once)
async function fast() {
  const [u1, u2] = await Promise.all([getUser(1), getUser(2)]);
}

