// try / catch / finally
try {
  const data = JSON.parse('invalid json');
} catch (error) {
  console.error(error instanceof SyntaxError); // true
  console.error(error.message); // 'Unexpected token i...'
} finally {
  console.log('Always runs — great for cleanup');
}

// Custom error class
class ValidationError extends Error {
  constructor(field, message) {
    super(message);
    this.name = 'ValidationError';
    this.field = field;
  }
}

function validateAge(age) {
  if (age < 0) throw new ValidationError('age', 'Age cannot be negative');
  return age;
}

try {
  validateAge(-1);
} catch (e) {
  if (e instanceof ValidationError) {
    console.log(`Field: ${e.field}, Error: ${e.message}`);
  } else {
    throw e; // re-throw unexpected errors
  }
}

