// Create dates
const now = new Date();
console.log(now.toISOString()); // '2025-06-15T10:30:00.000Z'

// Month is 0-indexed!
const birthday = new Date(2000, 0, 15); // 15 January 2000
console.log(birthday.getFullYear()); // 2000
console.log(birthday.getMonth());    // 0 (January!)
console.log(birthday.getDate());     // 15

// Timestamp (milliseconds since epoch)
console.log(Date.now()); // e.g. 1718441400000

// Date arithmetic — days between two dates
const start = new Date('2025-01-01');
const end   = new Date('2025-12-31');
const diffMs   = end - start;
const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24));
console.log(diffDays); // 364

// Locale-aware formatting
console.log(now.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' }));
// e.g. 'Sunday, June 15'

