js.fetch_api.code_example:
// GET request
async function getUser(id) {
  const response = await fetch(`https://api.example.com/users/${id}`);
  if (!response.ok) {
    throw new Error(`HTTP error: ${response.status}`);
  }
  const user = await response.json();
  return user;
}

// POST request
async function createUser(userData) {
  const response = await fetch('https://api.example.com/users', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer your-token'
    },
    body: JSON.stringify(userData)
  });
  if (!response.ok) throw new Error('Failed to create user');
  return response.json();
}

// Usage
try {
  const user = await getUser(1);
  console.log(user);
} catch (err) {
  console.error('Request failed:', err.message);
}

js.local_storage.code_example:
// Store data
localStorage.setItem('username', 'Alice');
localStorage.setItem('score', '95'); // strings only!

// Store object — must JSON.stringify
const prefs = { theme: 'dark', lang: 'en' };
localStorage.setItem('prefs', JSON.stringify(prefs));

// Retrieve data
const username = localStorage.getItem('username');
console.log(username); // 'Alice'

// Retrieve and parse object
const savedPrefs = JSON.parse(localStorage.getItem('prefs'));
console.log(savedPrefs.theme); // 'dark'

// Handle missing data
const val = localStorage.getItem('missing') ?? 'default';
console.log(val); // 'default'

// Remove
localStorage.removeItem('username');

// Clear everything
localStorage.clear();

// sessionStorage — same API, tab-only persistence
sessionStorage.setItem('token', 'abc123');
